"use strict";(self.webpackChunkdst_api_webdocs=self.webpackChunkdst_api_webdocs||[]).push([["492324"],{421418(e){e.exports=JSON.parse('{"tag":{"label":"light","permalink":"/dst-api-webdocs/docs/tags/light","allTagsPath":"/dst-api-webdocs/docs/tags","count":46,"items":[{"id":"game-scripts/prefabs/alterguardianhatshard","title":"Alterguardianhatshard","description":"A portable light-emitting storage container that holds a single Mushroom Spore and adjusts its light colour and appearance based on the spore type.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/alterguardianhatshard"},{"id":"game-scripts/prefabs/booklight","title":"Booklight","description":"A temporary light source prefab that fades out after a set duration, used for visual effects in cave transitions or events.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/booklight"},{"id":"game-scripts/prefabs/carnivaldecor_lamp","title":"Carnivaldecor Lamp","description":"A reusable decorative light fixture that can be activated via manual interaction or token insertion, emitting light and playing animations while supporting save/load, hammering, and trading.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/carnivaldecor_lamp"},{"id":"game-scripts/prefabs/chesterlight","title":"Chesterlight","description":"Manages the animated light source for Chester\'s Eye, dynamically adjusting radius and animation state when turned on or off.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/chesterlight"},{"id":"game-scripts/prefabs/creepyeyes","title":"Creepyeyes","description":"Spawns temporary, light-sensitive visual FX entities that appear in darkness and disappear when a player comes near or lights up.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/creepyeyes"},{"id":"game-scripts/prefabs/critterbuff_lunarmoth","title":"Critterbuff Lunarmoth","description":"Creates a temporary lighting FX entity that fades in/out and flickers to simulate a lunar moth\'s glow effect.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/critterbuff_lunarmoth"},{"id":"game-scripts/prefabs/decor_flowervase","title":"Decor Flowervase","description":"A decorative container component that holds and displays flowers, providing light, sanity effects, and inventory interactions when properly equipped.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/decor_flowervase"},{"id":"game-scripts/prefabs/decor_lamp","title":"Decor Lamp","description":"A decorative lantern prefab that provides adjustable ambient light and consumes cave fuel when active.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/decor_lamp"},{"id":"game-scripts/prefabs/electric_charged_fx","title":"Electric Charged Fx","description":"Generates a transient visual and lighting effect that simulates an electric discharge, optionally binding to a target entity to produce a flashing tint effect.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/electric_charged_fx"},{"id":"game-scripts/prefabs/endtable","title":"Endtable","description":"A decorative and functional structure that can hold flowers and emit light, with built-in durability and destruction handling.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/endtable"},{"id":"game-scripts/prefabs/eyeturret","title":"Eyeturret","description":"A deployable companion turret that automatically engages enemies within range, emits a dynamic light, and shares aggro with nearby turrets.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/eyeturret"},{"id":"game-scripts/behaviours/findlight","title":"Findlight","description":"A behavior tree node that moves an entity toward the nearest valid light source and maintains a safe distance within it.","permalink":"/dst-api-webdocs/docs/game-scripts/behaviours/findlight"},{"id":"game-scripts/prefabs/firefx_light","title":"Firefx Light","description":"Creates a lightweight, non-persistent visual light effect for use as a transient fire-related FX entity.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/firefx_light"},{"id":"game-scripts/prefabs/floatinglantern","title":"Floatinglantern","description":"Manages a flying lantern prefab that consumes fuel to stay airborne and emits light with dynamic physics-based behavior.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/floatinglantern"},{"id":"game-scripts/prefabs/flower_cave","title":"Flower Cave","description":"Manages a light-emitting, harvestable cave plant that cycles between active, recharging, and idle states based on environmental light levels.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/flower_cave"},{"id":"game-scripts/prefabs/forcefieldfx","title":"Forcefieldfx","description":"Renders a visual and lighting effect for a forcefield, animating its opening/closing and managing dynamic light intensity.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/forcefieldfx"},{"id":"game-scripts/prefabs/ghost_transform_overlay_fx","title":"Ghost Transform Overlay Fx","description":"Renders a visual overlay effect (light and animation) used during player ghost transformation sequences.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/ghost_transform_overlay_fx"},{"id":"game-scripts/prefabs/heatrock","title":"Heatrock","description":"Manages thermal energy storage and emission for the Heat Rock item, dynamically adjusting insulation, heating behavior, visuals, and light intensity based on environmental temperature.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/heatrock"},{"id":"game-scripts/prefabs/hutch","title":"Hutch","description":"Manages the Chester hutch entity, a companion that transforms between forms based on inventory batteries and provides light, damage reflection, and sanity effects.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/hutch"},{"id":"game-scripts/prefabs/lavae_pet","title":"Lavae Pet","description":"Manages the behavior, stats, and interactions of the Lavae pet companion in DST, including hunger-based heat/light regulation, sleep cycles, and ability to accept ashes for feeding.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/lavae_pet"},{"id":"game-scripts/prefabs/lightcrab","title":"Lightcrab","description":"A small, glowing amphibious creature that emits light and drops loot upon death.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/lightcrab"},{"id":"game-scripts/prefabs/lightflier","title":"Lightflier","description":"A bioluminescent flying insect prefab that forms formations around players carrying lightbulbs and provides ambient light.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/lightflier"},{"id":"game-scripts/prefabs/lightflier_flower","title":"Lightflier Flower","description":"A dynamic plant prefab that hosts and manages lightflier spawnlings, toggles light emission based on environmental illumination, and coordinates lifecycle events with its children.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/lightflier_flower"},{"id":"game-scripts/components/lighttweener","title":"Lighttweener","description":"Interpolates light properties (radius, intensity, falloff, colour) over time for an entity\'s attached light component.","permalink":"/dst-api-webdocs/docs/game-scripts/components/lighttweener"},{"id":"game-scripts/components/maxlightspawner","title":"Maxlightspawner","description":"Spawns and manages a fixed number of light prefabs in a circular pattern around an entity.","permalink":"/dst-api-webdocs/docs/game-scripts/components/maxlightspawner"},{"id":"game-scripts/prefabs/miniboatlantern","title":"Miniboatlantern","description":"A portable magical lantern that provides light, boosts wearer movement speed, and consumes magic fuel over time while active.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/miniboatlantern"},{"id":"game-scripts/prefabs/miniflare","title":"Miniflare","description":"A portable throwable flare item that ignites, emits light, triggers visual/audio effects, and notifies nearby players upon detonation.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/miniflare"},{"id":"game-scripts/prefabs/nightstick","title":"Nightstick","description":"Prefab definition for the Nightstick weapon that provides light, electric damage, and can be recharged with batteries.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/nightstick"},{"id":"game-scripts/prefabs/quagmire_lamp_post","title":"Quagmire Lamp Post","description":"Creates light-emitting environment assets for the Quagmire biome with predefined visual and luminance properties.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/quagmire_lamp_post"},{"id":"game-scripts/prefabs/redlantern","title":"Redlantern","description":"A magical lantern that emits light and consumes fuel over time; supports equipping, rain exposure handling, and dynamic visual effects via attached child entities.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/redlantern"},{"id":"game-scripts/prefabs/rock_light","title":"Rock Light","description":"A durable, fueled light source that transitions between burn states based on fuel level and can trigger a controlled explosion when fully depleted.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/rock_light"},{"id":"game-scripts/prefabs/slurper","title":"Slurper","description":"Equippable monster hat that attaches to characters, drains their hunger or health, and emits a pulsing light; it also acts as a hostile, autonomous creature when unequipped.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/slurper"},{"id":"game-scripts/prefabs/spawnlight_multiplayer","title":"Spawnlight Multiplayer","description":"A temporary visual FX entity that emits a pulsating light in multiplayer, synchronized across clients with server-authoritative timing and automatic cleanup after fading out.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/spawnlight_multiplayer"},{"id":"game-scripts/prefabs/stafflight","title":"Stafflight","description":"Creates staff-powered light-emitting entities with dynamic lighting, heating/cooling, sanity aura, and timed extinguishing behavior.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/stafflight"},{"id":"game-scripts/brains/stagehandbrain","title":"Stagehandbrain","description":"Implements AI behavior for the Stagehand entity, prioritizing panic responses at night while seeking nearby light sources.","permalink":"/dst-api-webdocs/docs/game-scripts/brains/stagehandbrain"},{"id":"game-scripts/prefabs/stalker_bulb","title":"Stalker Bulb","description":"Manages the lifecycle of a stalker flower, including bloom phase, fading light effects, and regenerative picking behavior in DST.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/stalker_bulb"},{"id":"game-scripts/prefabs/table_winters_feast","title":"Table Winters Feast","description":"Manages festive table functionality including food\u653E\u7F6E, seasonal feast registration, lighting effects, and interaction with the Winters Feast event system.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/table_winters_feast"},{"id":"game-scripts/prefabs/thurible","title":"Thurible","description":"Manages the behavior and state of the Thurible item, a lantern that lights up in the Dark and attracts Shadow Creatures.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/thurible"},{"id":"game-scripts/prefabs/torch","title":"Torch","description":"Manages the torch item\u2019s lighting, fuel consumption, ignited state, and interaction with Wilson\u2019s skilltree upgrades.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/torch"},{"id":"game-scripts/prefabs/torchfire_common","title":"Torchfire Common","description":"Provides utilities for creating and managing torchlight entities with animated fire effects, networked light range controls, and parented light synchronization.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/torchfire_common"},{"id":"game-scripts/prefabs/torchfire_pillar","title":"Torchfire Pillar","description":"Defines a persistent fire effect for torchfire pillars using custom particle emitters and visual envelopes.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/torchfire_pillar"},{"id":"game-scripts/prefabs/torchfire_pronged","title":"Torchfire Pronged","description":"A fire effect component that generates visual particle effects (smoke, fire, and embers) for a pronged torch variant, built using the shared torchfire system.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/torchfire_pronged"},{"id":"game-scripts/prefabs/vaultrelic","title":"Vaultrelic","description":"A collectible decorative item that can be placed on furniture, decorated with flowers, and repaired; it provides ambient light and sanity benefits when freshly decorated.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/vaultrelic"},{"id":"game-scripts/prefabs/wormlight","title":"Wormlight","description":"Manages the lifecycle and visual effects of a consumable light source that transfers to a player or creature upon eating, providing light while it lasts before extinguishing.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/wormlight"},{"id":"game-scripts/prefabs/wormlight_plant","title":"Wormlight Plant","description":"A harvestable light-emitting plant that regenerates after being picked and spawns a wormlight_lesser item.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/wormlight_plant"},{"id":"game-scripts/prefabs/yots_lantern_post","title":"Yots Lantern Post","description":"Manages a deployable post that connects to nearby posts, holds light-emitting batteries, and dynamically spawns suspended lantern chains with flickering light effects.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/yots_lantern_post"}],"unlisted":false}}')}}]);